package com.codelens.entity;import jakarta.persistence.*;import lombok.*;@Entity @Table(name="review_comments") @Getter @Setter @NoArgsConstructor public class ReviewCommentEntity{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) Long id; @ManyToOne(optional=false) PullRequestEntity pullRequest; String filePath; Integer lineNumber; String severity; @Column(length=4000) String message; String postStatus="PENDING";}
